// Compliant: Extract long case logic into separate functions
func processUserAction(action string, user User) error {
    switch action {
    case "create":
        return createUser(user)
    case "update":
        return updateUser(user)
    case "delete":
        return deleteUser(user.ID)
    default:
        return errors.New("unknown action")
    }
}

func createUser(user User) error {
    if err := validateUserData(user); err != nil {
        return err
    }

    if err := hashUserPassword(&user); err != nil {
        return fmt.Errorf("failed to hash password: %w", err)
    }

    setUserTimestamps(&user)
    user.Status = "active"

    if err := db.Create(&user).Error; err != nil {
        return fmt.Errorf("failed to create user: %w", err)
    }

    postCreateActions(user)
    return nil
}

func updateUser(user User) error {
    existingUser, err := getUserByID(user.ID)
    if err != nil {
        return fmt.Errorf("user not found: %w", err)
    }

    if err := mergeUserData(&existingUser, user); err != nil {
        return err
    }

    existingUser.UpdatedAt = time.Now()

    if err := db.Save(&existingUser).Error; err != nil {
        return fmt.Errorf("failed to update user: %w", err)
    }

    postUpdateActions(existingUser)
    return nil
}

func deleteUser(userID int) error {
    existingUser, err := getUserByID(userID)
    if err != nil {
        return fmt.Errorf("user not found: %w", err)
    }

    if existingUser.Status == "deleted" {
        return errors.New("user already deleted")
    }

    if err := performSoftDelete(&existingUser); err != nil {
        return err
    }

    cleanupUserData(userID)
    postDeleteActions(existingUser)
    return nil
}

// Helper functions for user operations
func validateUserData(user User) error {
    if user.Name == "" {
        return errors.New("name is required")
    }
    if user.Email == "" {
        return errors.New("email is required")
    }
    if !isValidEmail(user.Email) {
        return errors.New("invalid email format")
    }
    return nil
}

func postCreateActions(user User) {
    log.Printf("User %s created successfully", user.Name)
    sendWelcomeEmail(user.Email)
    incrementUserCount()
    auditLog("user_created", user.ID)
}

